                d.push({
                    title: 'в–¶ з«ӢеҚіж’ӯж”ҫ',
                    url: MY_URL + '@lazyRule=.js:' + LAZY_CODE,
                    col_type: 'text_center_1'
                });
            }

            var poster = '';
            var title = '';
