            var epsM = (html.match(/Episodes:<\/td>\s*<td[^>]*>([^<]+)</) || [])[1] || '';
            var meta = [
                castM && 'дё»жј”: ' + castM,
                genreM && 'зұ»еһӢ: ' + genreM,
                epsM && 'йӣҶж•°: ' + epsM.trim(),
                yearM && 'е№ҙд»Ҫ: ' + yearM.trim()
