                    pic_url: poster,
                    desc: meta || '',
                    url: MY_URL,
                    col_type: 'movie_1_vertical_pic'
                });
            }
            if (meta) d.push({ title: meta, col_type: 'rich_text' });

            // ж”¶йӣҶйҖүйӣҶ
