                        try {
                            // li ж•ҙж®өеҺ» HTML еҗҺзҡ„зәҜж–Үжң¬жңҖзЁі, е…је®№ж—ҘжңҹеңЁ a еҶ…/еӨ–дёӨз§Қз»“жһ„
                            var liText = (li + '').replace(/<[^>]*>/g, ' ').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
