            if (allEps.length === 0 && !directMp4) {
                d.push({title: 'жӯӨй ҒйқўйқһеҠҮйӣҶдё»йЎҢй Ғ,жңӘзҷјзҸҫйҒёйӣҶеҲ—иЎЁгҖӮ\nеҰӮйңҖж’ӯж”ҫ,и«ӢеҫһйҰ–й ҒеҲҶйЎһйҖІе…Ҙе°ҚжҮүеҠҮйӣҶгҖӮ', col_type: 'rich_text'});
            }

            // зәҝи·ҜжҢүй’®: Part 1/2/3
            if (allEps.length > 0) {
                var curLine = parseInt(getVar('sugo_part') || '1');
                for (var li2 = 1; li2 <= 3; li2++) {
                    var lab = 'Part ' + li2;
